// Summary: Validates Chip renders span label, optional icon wrapper aria-hidden, aria-label override, and style token application.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen } from '@testing-library/react';
// Using Jest's global describe, it, expect; no imports needed
import { Chip } from './Chip';

describe('Chip', () => {
  it('renders root span with provided label text', () => {
    render(<Chip label="General Admission" />);
    expect(screen.getByText('General Admission').tagName).toBe('SPAN');
  });

  it('renders icon wrapper with aria-hidden true when icon provided', () => {
    const { container } = render(
      <Chip label="With Icon" icon={<span data-testid="chip-icon">★</span>} />
    );
    const iconWrapper = container.querySelector('span[aria-hidden="true"]');
    expect(iconWrapper?.getAttribute('aria-hidden')).toBe('true');
  });

  it('applies aria-label override when provided', () => {
    render(<Chip label="GA" ariaLabel="General Admission" />);
    const root = screen.getByText('GA').parentElement as HTMLSpanElement;
    expect(root).toHaveAttribute('aria-label', 'General Admission');
  });

  it('applies base and icon slot class tokens', () => {
    const { container } = render(
      <Chip label="Inline" icon={<span data-testid="decorative-icon">☆</span>} />
    );
    const root = screen.getByText('Inline').parentElement as HTMLSpanElement;
    const iconWrapper = container.querySelector('span[aria-hidden="true"]');
    const classTokensApplied =
      root.className.includes('inline-flex') &&
      (iconWrapper?.className.includes('[&>svg]:size-4') ?? false);
    expect(classTokensApplied).toBe(true);
  });
});
